const express = require('express');
const bodyParser = require('body-parser');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const app = express();
const PORT = process.env.PORT || 3000;

app.use(bodyParser.json());

const limiter = rateLimit({
  windowMs: 1 * 60 * 1000,
  max: 100,
});
app.use(limiter);

const SECRET_KEY = process.env.SECRET_KEY || 'your_secret_key';

const validateLevelCompletion = (data) => {
  const { level, score, time } = data;
  if (typeof level !== 'number' || level <= 0) return false;
  if (typeof score !== 'number' || score < 0) return false;
  if (typeof time !== 'number' || time < 0) return false;
  return true;
};

const calculateReward = (score) => {
  if (score >= 1000) return 'Gold';
  if (score >= 500) return 'Silver';
  return 'Bronze';
};

app.post('/api/complete-level', (req, res) => {
  const token = req.headers['authorization'];
  if (!token) return res.status(401).json({ message: 'Unauthorized' });

  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) return res.status(403).json({ message: 'Forbidden' });

    const levelData = req.body;
    if (!validateLevelCompletion(levelData)) {
      return res.status(400).json({ message: 'Invalid level completion data' });
    }

    const reward = calculateReward(levelData.score);
    // Here you would typically save the level completion and reward to a database

    res.status(200).json({ message: 'Level completed', reward });
  });
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});